$env:ANYSCALE_HOST="https://console.azure.anyscale.com"; $env:ANYSCALE_CLI_TOKEN=""; $raw = anyscale cloud list --json --no-interactive --max-items 200; $parsed = $raw | ConvertFrom-Json; $clouds = @(); if ($parsed -is [System.Array]) { $clouds = $parsed } elseif ($parsed.clouds) { $clouds = $parsed.clouds } elseif ($parsed.items) { $clouds = $parsed.items } else { $clouds = @($parsed) }; function Get-BaseName([string]$n){ if (-not $n){ return $n }; if ($n -match '/providers/anyscale\.platform/clouds/([^/]+)$'){ return $matches[1] }; return $n }; $targets = @($clouds | Where-Object { (Get-BaseName $_.name) -match 'vibhansa' }); if ($targets.Count -eq 0) { Write-Host "NO_MATCHES"; exit 0 }; $targets | ForEach-Object { $base = Get-BaseName $_.name; Write-Host ("CLOUD|" + $_.name + "|" + $base + "|" + $_.id) }